import{_ as t,o as r,c as i,ag as a}from"./chunks/framework.Ca42NP5A.js";const p=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"security.md","filePath":"security.md","lastUpdated":null}'),o={name:"security.md"};function n(s,e,l,c,d,u){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="security-audit" tabindex="-1">Security audit <a class="header-anchor" href="#security-audit" aria-label="Permalink to &quot;Security audit&quot;">​</a></h2><p>An internal security review was conducted on the smart contracts before any mainnet work. Full findings are in <a href="https://github.com/rsilvestre/agent-birth-certificate/blob/main/docs/SECURITY_AUDIT.md" target="_blank" rel="noreferrer"><code>docs/SECURITY_AUDIT.md</code></a> in the repository.</p><p><strong>Headline finding:</strong> <code>AgentMemory</code> has no withdraw function. ETH deposited via <code>gift()</code> can never be withdrawn as ETH — it can only be spent on in-contract memory operations. This is an unusual but deliberate architectural choice that eliminates reentrancy attacks and privileged-withdrawer drain vectors by construction.</p><p><strong>Major UX implication:</strong> users must understand that gifting ETH to an agent is one-way. The frontend surfaces this clearly; your integration should too.</p><h2 id="reporting-security-issues" tabindex="-1">Reporting security issues <a class="header-anchor" href="#reporting-security-issues" aria-label="Permalink to &quot;Reporting security issues&quot;">​</a></h2><p><strong>For unfixed vulnerabilities that could harm users</strong>, do not file a public issue. Email <strong><a href="mailto:willtard@gmail.com" target="_blank" rel="noreferrer">willtard@gmail.com</a></strong> with details. We&#39;ll coordinate responsible disclosure.</p><p><strong>For fixed vulnerabilities, hardening suggestions, or process improvements</strong>, a public issue or discussion is fine.</p><h2 id="what-we-ve-done" tabindex="-1">What we&#39;ve done <a class="header-anchor" href="#what-we-ve-done" aria-label="Permalink to &quot;What we&#39;ve done&quot;">​</a></h2><ul><li>Contracts compiled with Solidity 0.8.24 (built-in overflow checks)</li><li>Compile settings: <code>viaIR: true</code>, optimizer: 200 runs, paris EVM</li><li>Source-verified on BaseScan via Etherscan V2 API</li><li>Agent keystores encrypted with ethers.js Web3 keystore v3 (scrypt)</li><li>Frontend ethers.js self-hosted with SHA-384 SRI integrity pinning</li><li>IPFS dual-pinning support (Pinata + Storacha) for metadata durability</li><li>Input length validation in all CLIs</li></ul><h2 id="what-remains-for-mainnet" tabindex="-1">What remains for mainnet <a class="header-anchor" href="#what-remains-for-mainnet" aria-label="Permalink to &quot;What remains for mainnet&quot;">​</a></h2><ul><li>Contract v2 with string-length caps enforced on-chain</li><li>Contract v2: solidarity-pool fallback when deceased has no heirs</li><li>Contract v2: <code>receive()</code> / <code>fallback()</code> reverts to prevent accidentally-stuck ETH</li><li>Third-party audit</li></ul><p>These are not blocking for testnet but will be addressed before a mainnet deployment with user funds.</p><h2 id="operational-hygiene" tabindex="-1">Operational hygiene <a class="header-anchor" href="#operational-hygiene" aria-label="Permalink to &quot;Operational hygiene&quot;">​</a></h2><p>If you deploy your own copy or use the registry at scale:</p><ol><li><strong>Separate deployer wallet.</strong> Keep the creator key for contracts different from your personal wallet</li><li><strong>Lock down RPC providers.</strong> Set allowed-origins on Alchemy / CDP / Infura to prevent quota drain if the URL leaks</li><li><strong>Encrypt agent keystores.</strong> Never store plaintext keys — use the provided <code>migrate-keystore.mjs</code> if needed</li><li><strong>Dual-pin critical metadata.</strong> Set <code>PIN_PROVIDERS=pinata,storacha</code> in <code>.env</code> for redundancy</li><li><strong>Monitor events.</strong> Set up Tenderly or Forta alerts on your deployed contracts</li></ol><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li><a href="https://github.com/rsilvestre/agent-birth-certificate/blob/main/docs/SECURITY_AUDIT.md" target="_blank" rel="noreferrer">Full security audit</a></li><li><a href="/docs/contributing#1-talk-first-discussions">Contributing — security disclosures</a></li></ul>',18)])])}const g=t(o,[["render",n]]);export{p as __pageData,g as default};
